1	import type { ZodType } from 'zod';
2	import type { AgentContext } from './context.js';
3	import { isRejection, PluginError, type Rejection } from './errors.js';
4	import type { FireResult } from './types.js';
5	import { withTimeout } from './util/with-timeout.js';
6	
7	export type ServiceHandler<I = unknown, O = unknown> = (
8	  ctx: AgentContext,
9	  input: I,
10	) => Promise<O>;
11	
12	export type SubscriberHandler<P = unknown> = (
13	  ctx: AgentContext,
14	  payload: P,
15	) => Promise<P | undefined | Rejection>;
16	
17	/** Default per-service-call timeout. A hang backstop, not a latency SLA. */
18	export const DEFAULT_SERVICE_TIMEOUT_MS = 120_000;
19	
20	export interface HookBusOptions {
21	  /** Default timeout applied to every service call without its own override. */
22	  defaultServiceTimeoutMs?: number;
23	}
24	
25	/**
26	 * A timeout is valid if it is `Infinity` (the explicit "no timeout" sentinel) or
27	 * a finite, non-negative number. We reject `NaN`, negatives, and `-Infinity`
28	 * loudly at config time: a negative delay clamps to ~1ms and would spuriously
29	 * time out every call, while `NaN`/`-Infinity` would silently disable the timer
30	 * and quietly drop the hang protection. Only `Infinity` may disable it, on purpose.
31	 */
32	function isValidTimeoutMs(value: number): boolean {
33	  return value === Number.POSITIVE_INFINITY || (Number.isFinite(value) && value >= 0);
34	}
35	
36	interface RegisteredService {
37	  plugin: string;
38	  handler: ServiceHandler;
39	  returns?: ZodType;
40	  timeoutMs?: number;
41	}
42	
43	interface RegisteredSubscriber {
44	  plugin: string;
45	  handler: SubscriberHandler;
46	}
47	
48	export class HookBus {
49	  private services = new Map<string, RegisteredService>();
50	  private subscribers = new Map<string, RegisteredSubscriber[]>();
51	  private readonly defaultServiceTimeoutMs: number;
52	
53	  constructor(opts?: HookBusOptions) {
54	    const configured = opts?.defaultServiceTimeoutMs ?? DEFAULT_SERVICE_TIMEOUT_MS;
55	    if (!isValidTimeoutMs(configured)) {
56	      throw new PluginError({
57	        code: 'invalid-payload',
58	        plugin: 'core',
59	        message: `HookBus defaultServiceTimeoutMs must be a non-negative finite number or Infinity (got ${configured})`,
60	      });
61	    }
62	    this.defaultServiceTimeoutMs = configured;
63	  }
64	
65	  registerService<I, O>(
66	    hookName: string,
67	    plugin: string,
68	    handler: ServiceHandler<I, O>,
69	    opts?: { returns?: ZodType<O>; timeoutMs?: number },
70	  ): void {
71	    const existing = this.services.get(hookName);
72	    if (existing !== undefined) {
73	      throw new PluginError({
74	        code: 'duplicate-service',
75	        plugin,
76	        message: `service hook '${hookName}' already registered by plugin '${existing.plugin}'`,
77	      });
